import assert from 'tjs:assert';
import path from 'tjs:path';

const encoder = new TextEncoder();
const tmpDir = await tjs.makeTempDir('repro_fswatch_gcXXXXXX');
const file = await tjs.makeTempFile(path.join(tmpDir, 'watchedXXXXXX'));
const watchedPath = file.path;
await file.close();

let retainedEvents = 0;
let unretainedEvents = 0;
let closedEvents = 0;

function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

const retained = tjs.watch(watchedPath, () => {
    retainedEvents++;
});

tjs.watch(watchedPath, () => {
    unretainedEvents++;
});

const closed = tjs.watch(watchedPath, () => {
    closedEvents++;
});
closed.close();

for (let i = 0; i < 5; i++) {
    tjs.gc.run();
    await sleep(50);
}

await tjs.writeFile(watchedPath, encoder.encode('first change'));
await sleep(1000);
await tjs.writeFile(watchedPath, encoder.encode('second change'));
await sleep(1000);

retained.close();
await tjs.remove(watchedPath);
await tjs.remove(tmpDir);

console.log(JSON.stringify({ retainedEvents, unretainedEvents, closedEvents }));
assert.ok(retainedEvents > 0, 'retained watcher should receive events');
assert.ok(unretainedEvents > 0, 'unretained watcher should survive GC and receive events');
assert.equal(closedEvents, 0, 'closed watcher should not receive events');
EOF
